// // This module finds the minimum value between two 4-bit inputs, A and B, on the falling edge of the clock signal.
module top_module(
    input clk,
    input [3:0] A,
    input [3:0] B,
    output reg [3:0] max,
    output reg max_sel
);always @(posedge clk) begin
    if (A > B) begin
        max <= A;
        max_sel <= 1;
    end else begin
        max <= B;
        max_sel <= 0;
    end
end

endmodule
